const body = $input.first().json.body || $input.first().json;
const fileId = (body.file_id || '').toString().trim();
const botToken = (body.bot_token || '').toString().trim();

if (!fileId || !botToken) {
  throw new Error('Missing required fields: file_id and bot_token');
}

return $input.all();

// Pass webhook body fields to WF1
const body = $('Webhook').first().json.body || $('Webhook').first().json;
return [{json: {
  file_id: (body.file_id || '').toString().trim(),
  bot_token: (body.bot_token || '').toString().trim(),
  meeting_name: body.meeting_name || 'Untitled Meeting',
  participants: body.participants || '',
  date: body.date || new Date().toISOString().slice(0, 10),
  start_time: body.start_time || '',
  queue_id: body.queue_id || '',
  end_time: body.end_time || '',
  chat_id: body.chat_id || ''
}}];

// Pass transcript + metadata to WF2
const wf1 = $('Run Transcribe').first().json;
const webhookData = $('Prep Transcribe Input').first().json;

// Calculate end_time from transcript last timestamp if not provided
let endTime = wf1.end_time || '';
if (!endTime && wf1.transcript && wf1.transcript.data) {
    const tsMatch = wf1.transcript.data.match(/\[(\d[\d:.]+)\s*(?:-->|->|–|—|-)\s*(\d[\d:.]+)\]/g);
    if (tsMatch && tsMatch.length > 0) {
        const last = tsMatch[tsMatch.length - 1];
        const endMatch = last.match(/(?:-->|->|–|—|-)\s*(\d[\d:.]+)/);
        if (endMatch) {
            const parts = endMatch[1].split(':');
            let totalSec = 0;
            if (parts.length === 3) totalSec = parseFloat(parts[0])*3600 + parseFloat(parts[1])*60 + parseFloat(parts[2]);
            else if (parts.length === 2) totalSec = parseFloat(parts[0])*60 + parseFloat(parts[1]);
            // Convert start_time + totalSec to HH:MM
            const startParts = (wf1.start_time || '08:00').split(':');
            const startSec = parseInt(startParts[0])*3600 + parseInt(startParts[1])*60;
            const endSec = startSec + totalSec;
            const endH = Math.floor(endSec / 3600);
            const endM = Math.floor((endSec % 3600) / 60);
            endTime = String(endH).padStart(2, '0') + ':' + String(endM).padStart(2, '0');
        }
    }
}

return [{json: {
  transcript: wf1.transcript,
  meeting_name: wf1.meeting_name,
  participants: wf1.participants,
  date: wf1.date,
  start_time: wf1.start_time,
  end_time: endTime,
  chat_id: webhookData.chat_id || '',
  queue_id: webhookData.queue_id || '',
  context: webhookData.context || '',
  file_id: wf1.file_id || '',
  bot_token: wf1.bot_token || ''
}}];

// Prepare shared input for Intel (WF3) and Extract (WF4)
const wf2 = $('Run Analyze').first().json;
return [{json: {
  meeting_name: wf2.meeting_name,
  participants: wf2.participants,
  date: wf2.date,
  start_time: wf2.start_time,
  minutesText: wf2.minutesText,
  assembledMinutesJson: wf2.assembledMinutesJson,
  topics: wf2.topics,
  analyzedTopics: wf2.analyzedTopics,
  transcript: wf2.transcript
}}];

// Re-fetch original downstream data for extract (serial flow: intel output ≠ extract input)
const wf2 = $('Prep Downstream Input').first().json;
return [{json: {
  minutesText: wf2.minutesText,
  meeting_name: wf2.meeting_name,
  participants: wf2.participants,
  date: wf2.date,
  start_time: wf2.start_time,
  bot_token: $('Run Transcribe').first().json.bot_token || ''
}}];

// Build Telegram notification from orchestrator data
const wf1 = $('Run Transcribe').first().json;
const wf2 = $('Run Analyze').first().json;
const webhookData = $('Prep Transcribe Input').first().json;

const meetingName = wf2.meeting_name || wf1.meeting_name || 'Unknown';
const date = wf2.date || wf1.date || '';
const topicCount = (wf2.topics || []).length;
const chatId = webhookData.chat_id || '';

// Build paths
const minutesPath = `100 - Meeting minutes/${date} ${meetingName}.md`;
const intelPath = `101 - Meeting Intelligence Reports/${date} ${meetingName} - Intelligence Report.md`;
const extractPath = `102 - Meeting Extracts/${date} ${meetingName} - Key Items.md`;

// Check if WF3/WF4 succeeded (continueOnFail means they might have error output)
const wf3Ok = !$('Run Intel Report').first().json?.error;
const wf4Ok = !$('Run Key Items Extract').first().json?.error;

let msg = `\ud83d\udcdd *Meeting minutes created*\n`;
msg += `\ud83d\udccb ${meetingName} (${date})\n`;
msg += `\ud83d\udcca ${topicCount} topic${topicCount !== 1 ? 's' : ''} analyzed\n\n`;
msg += `\ud83d\udcc4 \`${minutesPath}\`\n`;

if (wf3Ok) {
  msg += `\ud83d\udd0d \`${intelPath}\`\n`;
} else {
  msg += `\u26a0\ufe0f Intel report failed\n`;
}

if (wf4Ok) {
  msg += `\ud83d\uddc2 \`${extractPath}\`\n`;
} else {
  msg += `\u26a0\ufe0f Key items extract failed\n`;
}

const body = {
  chat_id: chatId,
  text: msg,
  parse_mode: 'Markdown'
};

return [{json: {body: JSON.stringify(body), bot_token: wf1.bot_token}}];

const fs = require('fs');
const wb = $('Prep Transcribe Input').first().json;
const queueId = wb.queue_id || 'unknown';
const meetingName = wb.meeting_name || '';
const doneDir = '/data/pipeline_done';
try { fs.mkdirSync(doneDir, { recursive: true }); } catch(e) {}
fs.writeFileSync(doneDir + '/' + queueId + '.json', JSON.stringify({
    queue_id: queueId,
    meeting_name: meetingName,
    status: 'complete',
    completed_at: new Date().toISOString()
}));
return $input.all();

const fs = require('fs');
let queueId = 'unknown';
let meetingName = '';
try {
    const wb = $('Prep Transcribe Input').first().json;
    queueId = wb.queue_id || 'unknown';
    meetingName = wb.meeting_name || '';
} catch(e) {}
const doneDir = '/data/pipeline_done';
try { fs.mkdirSync(doneDir, { recursive: true }); } catch(e) {}
const errorMsg = $input.first().json.execution?.error?.message || 'unknown error';
fs.writeFileSync(doneDir + '/' + queueId + '.json', JSON.stringify({
    queue_id: queueId,
    meeting_name: meetingName,
    status: 'failed',
    completed_at: new Date().toISOString(),
    error: errorMsg
}));
return [{json: {queue_id: queueId, status: 'failed', error: errorMsg}}];
